-- Enforce constraints at table level
ALTER TABLE orders ADD CONSTRAINT valid_status CHECK (status IN ('pending', 'shipped', 'cancelled'));
ALTER TABLE orders CHANGE COLUMN customer_id customer_id BIGINT NOT NULL;

-- Idempotent deduplication via MERGE
MERGE INTO orders AS target
USING (
  SELECT * FROM raw_orders
  QUALIFY ROW_NUMBER() OVER (PARTITION BY order_id ORDER BY updated_at DESC) = 1
) AS source
ON target.order_id = source.order_id
WHEN MATCHED THEN UPDATE SET *
WHEN NOT MATCHED THEN INSERT *;

-- Row filter: analysts only see their region's data
CREATE FUNCTION catalog.security.region_filter(region STRING)
  RETURN region = current_user_region() OR IS_ACCOUNT_GROUP_MEMBER('data-admins');

ALTER TABLE catalog.sales.orders
  SET ROW FILTER catalog.security.region_filter ON (region);

-- Column mask: hide raw PII from non-PII roles
CREATE FUNCTION catalog.security.mask_email(email STRING)
  RETURN CASE WHEN IS_ACCOUNT_GROUP_MEMBER('pii-access')
    THEN email ELSE regexp_replace(email, '(.).+(@.+)', '$1***$2') END;

ALTER TABLE catalog.sales.customers
  ALTER COLUMN email SET MASK catalog.security.mask_email;

-- RBAC: grant SELECT to analyst group, never to individuals
GRANT SELECT ON TABLE catalog.sales.orders TO `data-analysts`;

-- Provider: create and populate a share
CREATE SHARE prod_analytics_share;

ALTER SHARE prod_analytics_share
  ADD TABLE catalog.sales.orders
  PARTITION (region = 'us-east-1');

-- Add a secure view instead of raw table
ALTER SHARE prod_analytics_share
  ADD VIEW catalog.sales.orders_masked;

-- Grant to a Unity Catalog recipient (cross-account)
CREATE RECIPIENT acme_corp
  USING ID 'databricks://acme.azuredatabricks.net/metastoreId';

GRANT SELECT ON SHARE prod_analytics_share TO RECIPIENT acme_corp;

-- Consumer mounts it as a local catalog
CREATE CATALOG acme_shared USING SHARE provider_metastore.prod_analytics_share;

import dlt
from pyspark.sql import functions as F

# DLT table registered in Unity Catalog — consumed by both Feature Store and BI
@dlt.table(
    name="main.data_warehouse.user_features",
    comment="Shared by ML Feature Store and Databricks SQL dashboards",
    table_properties={"delta.enableChangeDataFeed": "true"}
)
def user_features():
    return (
        dlt.read("main.bronze.events")
            .groupBy("user_id")
            .agg(
                F.count("event_id").alias("event_count_30d"),
                F.avg("session_duration").alias("avg_session_duration")
            )
    )
